INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("春咲 ひより", 0, 1001, 1.4, 2, 0, 1, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 0, "お！\nあそこに困ってそうな人発見！", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("草野 優衣", 0, 1002, 1.4, 2, 0, 1, "みんなみたいに\nわたしも強くならなきゃ", 0, "わ、わたし、\nなに言ってるんだろ\nあはは…", 0, "大切な人を\n守れるようになりたい…って", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("士条 怜", 0, 1003, 1.4, 2, 0, 1, "フェンシングを始めてみては？", 0, "少しは磨かれると思いますよ。", 0, "キミに必要な集中力と感性が", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("穂高 みそぎ", 0, 1004, 1.5, 2, 0, 1, "ねぇ、にいちゃん！", 0, "みそぎはねぇ、\nかくれんぼやりたい！", 0, "今日はなにして遊ぶ？", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("風宮 あかり", 0, 1006, 1.4, 2, 0, 1, "風宮あかりです", 0, "私といっしょに…\nいかない？", 0, "ねぇ…", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("出雲 宮子", 0, 1007, 1.5, 2, 0, 1, "出雲宮子なのー", 0, "食べ物の恨みは怖いのー", 0, "プリンたべたいのー", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("虹村 雪", 0, 1008, 1.4, 2, 0, 1, "ボクは虹村雪。", 0, "いいよ。\n見られることは運命さ…", 0, "キミもボクの美貌に\n吸い寄せられたんだね。", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("柊杏奈", 0, 1009, 1.4, 2, 0, 1, "フッ…聞いて後悔するがいい！", 0, "人呼んで「疾風の冥姫」!!", 0, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("姫宮 真歩", 0, 1010, 1.5, 2, 0, 1, "マホマホ王国のプリンセス、\nまほ姫どす", 0, "ほんまおおきにやわ～♪", 0, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("衣之咲 璃乃", 0, 1011, 1.4, 2, 0, 1, "衣之咲璃乃です！", 0, "ここで会ったが\n100年目～！", 0, "生き別れたお兄ちゃんを探して\n三千世界！", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("柏崎 初音", 0, 1012, 1.4, 2, 0, 1, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, "…って、お願い！\n誰にも言わないでおいて～！", 0, "ち、超能力って…\n何のことかな～？", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("美波 鈴奈", 0, 1016, 1.4, 2, 0, 1, "ちょす！\n美波鈴奈だよ～♪", 0, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 0, "一応カリスマ読モJKやってまっす！", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("喜屋武 香織", 0, 1017, 1.4, 2, 0, 1, "はいたーい。\n喜屋武香織さー。", 0, "でも、沖縄もとってもいいとこさー", 0, "東京は遊園地みたいなところさー", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("支倉 伊緒", 0, 1018, 1.4, 2, 0, 1, "支倉伊緒です。", 0, "イオちゃんって呼んでね。", 0, "先生って呼ばれるのは\nくすぐったいから", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("茜 ミミ", 0, 1020, 1.5, 2, 0, 1, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, "ミミをおいてかないでぇ～", 0, "あ！/\お兄ちゃ～ん\nまってよ～", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("栗林 くるみ", 0, 1021, 1.5, 2, 0, 1, "あ…あの…えっと…\n栗…林…くるみ…です……", 0, "ふぇぇぇぇぇん……", 0, "あの……\nふぇ……", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("風宮 より", 0, 1022, 1.4, 2, 0, 1, "風宮よりです。\nあああああ！", 0, "なんてありがとうございます！", 0, "こんな私に貴重な時間を\n割いていただき、", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("北条 綾音", 0, 1023, 1.5, 2, 0, 1, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, "私こっち行きたいー\nね、早く早くー", 0, "おにいちゃんどこいくの？\nえ？", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("天野 すずめ", 0, 1025, 1.4, 2, 0, 1, "わっ…わっ…私、\n天野すずめといいます！", 0, "これて何か違う…\nあああすみません！", 0, "ふ、不束者ですが\nどうぞ末永く…って、", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("倉石 恵理子", 0, 1027, 1.4, 2, 0, 1, "……クスクス…私は\n…倉石恵理子……", 0, "離しませんわ………\n絶対に…!!", 0, "あなたは…運命の……\n伴侶……", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("佐々木 咲恋", 0, 1028, 1.4, 2, 0, 1, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, "…そうでしょ？？", 0, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("桜井 望", 0, 1029, 1.4, 2, 0, 1, "桜井望だよ！\nよろしくねっ", 0, "あはは、\n私もまだまだだなぁ～", 0, "ぇっと…\nキミ、私のこと知らないの?!", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("ニノン・ジュベール", 0, 1030, 1.4, 2, 0, 1, "デケデケデンっ！", 0, "ショーグン、\nワタシと一緒に天下統一デース！", 0, "初めまして、\n私はニノン・ジュベール申すデス！", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("上喜 しのぶ", 0, 1031, 1.4, 2, 0, 1, "上喜しのぶです。\n手元のドクロが父です。", 0, "おかしいですね……", 0, "でもって私の隣にいるのが……\nえ、見えない？", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("野戸まひる", 0, 1033, 1.5, 2, 0, 1, "目指すはビッグな\nお笑い芸人だっぺ！", 0, "そう、\nオラのボケに突っ込める相方が…！", 0, "けんども\nそれには足りないモンが…", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("綾瀬 ゆかり", 0, 1034, 1.4, 2, 0, 1, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, "ちょ\nちょっと一杯飲んできます…！", 0, "ちょっと緊張しちゃって…", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("氷川 鏡華", 0, 1036, 1.5, 2, 0, 1, "氷川鏡華…です", 0, "これ以上お話しすることは…\nないです！", 0, "知らない人とは話しちゃいけないので", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("柏崎 栞", 0, 1038, 1.4, 2, 0, 1, "柏崎…栞です。", 0, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 0, "……あ、アラーム。", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("双葉 碧", 0, 1040, 1.4, 2, 0, 1, "ふ、双葉碧です。", 0, "野に咲く花が、\n唯一の話相手です。", 0, "私、一人も友達がいなくて……", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("三角 千歌", 0, 1042, 1.4, 2, 0, 1, "三角千歌です。", 0, "そう思っています。", 0, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("安芸 真琴", 0, 1043, 1.4, 2, 0, 1, "安芸真琴だ。", 0, "う、疑ってすまなかったな…", 0, "あぁ？\nお前のそいつの仲間か？", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("イリヤ・オーンスタイン", 0, 1044, 1.4, 2, 0, 1, "わらわこそは夜を総べる者！", 0, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 0, "生けとし生ける全ての者よ！", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("遠見 空花", 0, 1045, 1.4, 2, 0, 1, "そこで騎士は妖精を乱暴に……", 0, "ｌク、クウカに何かご用ですか!?", 0, "ぐふふふふ……はっ！", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("宮坂たまき", 0, 1046, 1.4, 2, 0, 1, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, "う～ん…\n猫ってホントに最高にゃ～♪", 0, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("大神 美冬", 0, 1048, 1.4, 2, 0, 1, "大神美冬よ！", 0, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 0, "それでは早速クエストに…", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("星野静流", 0, 1049, 1.4, 2, 0, 1, "星野静流だよ！", 0, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 0, "クエストもバトルも\n掃除も洗濯も", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("玉泉美咲", 0, 1050, 1.5, 2, 0, 1, "アタシは玉泉美咲。", 0, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 0, "見ての通りの\nセクシー美少女で", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("リマ", 0, 1052, 1.4, 2, 0, 1, "？？？", 0, "？？？？", 0, "？？？？", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("モニカ・ヴァイスヴィント", 0, 1053, 1.5, 2, 0, 1, "モニカ・ヴァイスヴィントだ。", 0, "そ、そこまでいうなら\nもらってやる", 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("ペコリーヌ", 0, 1058, 1.5, 2, 0, 1, "モニカ・ヴァイスヴィントだ。", 0, "そ、そこまでいうなら\nもらってやる", 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("コッコロ", 0, 1059, 1.5, 2, 0, 1, "モニカ・ヴァイスヴィントだ。", 0, "そ、そこまでいうなら\nもらってやる", 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 1);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES ("キャル", 0, 1060, 1.5, 2, 0, 1, "モニカ・ヴァイスヴィントだ。", 0, "そ、そこまでいうなら\nもらってやる", 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 1);
